class Solution(object):
    def luckyNumbers(self, matrix):
        row_mins = [min(row) for row in matrix]
        col_maxs = [max(matrix[i][j] for i in range(len(matrix))) for j in range(len(matrix[0]))]
        lucky = set(row_mins) & set(col_maxs)
        return list(lucky)
